from ariadne import gql, make_executable_schema, QueryType, ObjectType
from ariadne.constants import PLAYGROUND_HTML
from ariadne.asgi import GraphQL
from starlette.applications import Starlette
from starlette.middleware import Middleware
from starlette.middleware.authentication import AuthenticationMiddleware
from starlette.authentication import AuthenticationBackend, AuthCredentials, UnauthenticatedUser
from starlette.requests import Request
import jwt
from typing import Optional, Dict, Any
from datetime import datetime, timedelta
import os

# Mock database
users_db = {
    1: {
        "id": 1,
        "username": "johndoe",
        "bio": "Software developer",
        "email": "john@example.com",
        "phone": "+1234567890",
        "address": "123 Main St"
    },
    2: {
        "id": 2,
        "username": "janedoe",
        "bio": "Designer",
        "email": "jane@example.com",
        "phone": "+0987654321",
        "address": "456 Oak Ave"
    }
}

# GraphQL schema
type_defs = gql("""
    type User {
        id: ID!
        username: String!
        bio: String!
        email: String
        phone: String
        address: String
    }

    type Post {
        id: ID!
        title: String!
        content: String!
        author: User!
    }

    type Query {
        user(id: ID!): User
        users: [User!]!
        me: User
    }
""")

# Resolvers
query = QueryType()

@query.field("user")
def resolve_user(_, info, id):
    user_id = int(id)
    user_data = users_db.get(user_id)
    if not user_data:
        return None
    return user_data

@query.field("users")
def resolve_users(_, info):
    return list(users_db.values())

@query.field("me")
def resolve_me(_, info):
    request = info.context["request"]
    current_user = getattr(request.state, "current_user", None)
    if not current_user:
        return None
    return users_db.get(current_user["id"])

# Authentication backend
class JWTAuthenticationBackend(AuthenticationBackend):
    async def authenticate(self, request: Request) -> Optional[AuthCredentials]:
        auth_header = request.headers.get("Authorization")
        if not auth_header:
            return None
            
        try:
            token = auth_header.split(" ")[1]
            payload = jwt.decode(token, os.getenv("SECRET_KEY"), algorithms=["HS256"])
            return AuthCredentials(["authenticated"], user=payload)
        except Exception:
            return None

# Type definitions for resolvers
user_type = ObjectType("User")

# GraphQL app
middleware = [
    Middleware(AuthenticationMiddleware, backend=JWTAuthenticationBackend())
]

schema = make_executable_schema(type_defs, [query, user_type])
graphql_app = GraphQL(schema, debug=True)

# Starlette app
app = Starlette(
    routes=[
        GraphQLRoute("/graphql", graphql_app, playground_options=PLAYGROUND_HTML),
    ],
    middleware=middleware
)